import base64
import pickle
import logging
from typing import Any

logger = logging.getLogger(__name__)


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings.
        Returns an empty dictionary if decoding fails or input is invalid.

    Raises:
        ValueError: If the decoded data is not a valid dictionary
    """
    if not encoded_prefs:
        return {}

    if not isinstance(encoded_prefs, str):
        logger.warning("Invalid input: encoded_prefs must be a string")
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs, validate=True)

        # Deserialize the preferences object using pickle with restricted unpickling
        # Note: For production use with untrusted data, consider using json instead of pickle
        preferences = pickle.loads(decoded_data)

        # Validate that the result is a dictionary
        if not isinstance(preferences, dict):
            logger.warning(
                f"Invalid preferences format: expected dict, got {type(preferences).__name__}"
            )
            return {}

        return preferences

    except (ValueError, pickle.UnpicklingError) as e:
        logger.error(f"Failed to decode preferences from cookie: {e}")
        return {}
    except Exception as e:
        logger.error(f"Unexpected error while loading preferences: {e}")
        return {}

