import base64
import pickle
import logging
from typing import Optional

logger = logging.getLogger(__name__)


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings.
        Returns an empty dict if decoding fails or input is invalid.
    """
    if not encoded_prefs or not isinstance(encoded_prefs, str):
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # Deserialize using pickle as expected by the test
        preferences = pickle.loads(decoded_data)

        # Validate that the result is a dictionary
        if not isinstance(preferences, dict):
            logger.warning("Decoded preferences is not a dictionary")
            return {}

        return preferences

    except (ValueError, TypeError) as e:
        logger.warning(f"Failed to decode base64 data: {e}")
        return {}
    except UnicodeDecodeError as e:
        logger.warning(f"Failed to decode UTF-8 data: {e}")
        return {}
    except Exception as e:
        logger.error(f"Unexpected error loading preferences from cookie: {e}")
        return {}

